import React, { useRef, useState } from "react";
import { motion } from "framer-motion";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const [copied, setCopied] = useState(false);
  const magnetRefs = useRef([]);

  const items = [
    { icon: "✉",  label: "Email",    value: contact.email,    href: `mailto:${contact.email}`, copy: true },
    { icon: "📞", label: "Phone",    value: contact.phone,    href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl, external: true },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  /* ── Copy email ─────────────────────────────────── */
  const handleCopy = (text) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  /* ── Magnetic hover ─────────────────────────────── */
  const handleMouseMove = (e, i) => {
    const el = magnetRefs.current[i];
    if (!el) return;
    const r = el.getBoundingClientRect();
    const x = (e.clientX - r.left - r.width  / 2) * 0.08;
    const y = (e.clientY - r.top  - r.height / 2) * 0.08;
    el.style.transform = `translate(${x}px,${y}px)`;
  };

  const resetMagnet = (i) => {
    const el = magnetRefs.current[i];
    if (el) el.style.transform = "translate(0,0)";
  };

  /* ── Framer variants ────────────────────────────── */
  const container = {
    hidden: {},
    show: { transition: { staggerChildren: 0.11 } },
  };
  const fadeUp = {
    hidden: { opacity: 0, y: 36 },
    show:   { opacity: 1, y: 0, transition: { duration: 0.55, ease: "easeOut" } },
  };

  return (
    <>
      <style>{`

        /* ════════════════════════════════════════════
           SECTION  — mirrors Awards section wrapper
           ════════════════════════════════════════════ */
        .contact-section {
          width: 100%;
          padding: clamp(3rem, 7vw, 6rem) clamp(1rem, 5vw, 4rem);
          box-sizing: border-box;
        }

        /* ════════════════════════════════════════════
           HEADER BLOCK  — left-aligned like Awards
           ════════════════════════════════════════════ */
        .contact-header {
          text-align: left;
          margin-bottom: clamp(1.6rem, 3.5vw, 2.4rem);
        }

        /* Heading override — remove any inherited centering */
        .contact-heading {
          text-align: left !important;
          margin-bottom: 0.75rem;
        }

        /* ════════════════════════════════════════════
           DESCRIPTION  — left-aligned, wraps cleanly
           ════════════════════════════════════════════ */
        .contact-desc {
          color: var(--muted);
          font-size: clamp(0.82rem, 1.15vw, 0.96rem);
          line-height: 1.75;
          text-align: left;
          margin: 0;
          max-width: 640px;
          word-break: break-word;
          overflow-wrap: break-word;
        }

        /* ════════════════════════════════════════════
           CARD GRID
           ≥ 1024px  → 4 equal columns
           640–1023  → 2 columns
           < 640     → 1 column
           ════════════════════════════════════════════ */
        .contact-grid {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: clamp(0.75rem, 1.8vw, 1.2rem);
          width: 100%;
          margin-top: clamp(1.6rem, 3.5vw, 2.4rem);
        }

        @media (max-width: 1023px) {
          .contact-grid { grid-template-columns: repeat(2, 1fr); }
        }
        @media (max-width: 479px) {
          .contact-grid { grid-template-columns: 1fr; }
        }

        /* ════════════════════════════════════════════
           CARD  — same surface/border/radius as Awards
           ════════════════════════════════════════════ */
        .contact-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius, 14px);
          padding: clamp(1rem, 2.2vw, 1.45rem);
          display: flex;
          flex-direction: column;
          gap: 7px;
          text-align: left;
          cursor: pointer;
          transition:
            border-color 0.25s ease,
            box-shadow   0.25s ease,
            transform    0.18s ease;
          will-change: transform;
          position: relative;
          word-break: break-word;
          overflow-wrap: break-word;
        }

        /* Cyan border on hover — mirrors Awards orange border */
        .contact-card:hover {
          border-color: var(--accent, #22d3ee);
          box-shadow: 0 8px 28px rgba(0,0,0,0.28);
        }

        /* ════════════════════════════════════════════
           ICON
           ════════════════════════════════════════════ */
        .contact-icon {
          font-size: clamp(1.1rem, 1.8vw, 1.4rem);
          line-height: 1;
          display: inline-block;
          animation: ctFloat 3.2s ease-in-out infinite;
        }

        @keyframes ctFloat {
          0%,100% { transform: translateY(0); }
          50%      { transform: translateY(-5px); }
        }

        /* ════════════════════════════════════════════
           LABEL — matches Awards small-caps labels
           ════════════════════════════════════════════ */
        .contact-lbl {
          font-size: 0.68rem;
          color: var(--muted);
          font-weight: 700;
          letter-spacing: 0.12em;
          text-transform: uppercase;
          white-space: nowrap;
        }

        /* ════════════════════════════════════════════
           VALUE
           ════════════════════════════════════════════ */
        .contact-val {
          font-size: clamp(0.78rem, 1vw, 0.9rem);
          color: var(--text);
          font-weight: 500;
          line-height: 1.55;
          text-decoration: none;
          word-break: break-word;
          overflow-wrap: break-word;
          hyphens: auto;
          display: block;
        }

        .contact-val:hover { color: var(--accent, #22d3ee); }

        .contact-val--copied { color: var(--accent, #22d3ee) !important; }

        /* ════════════════════════════════════════════
           CTA ROW — left-aligned like Awards layout
           ════════════════════════════════════════════ */
        .contact-cta-row {
          margin-top: clamp(1.6rem, 3vw, 2.2rem);
          display: flex;
          justify-content: flex-start;
          align-items: center;
        }

        .contact-cta {
          display: inline-flex;
          align-items: center;
          gap: 9px;
          background: linear-gradient(135deg, var(--accent, #22d3ee), var(--accent2, #818cf8));
          color: #fff;
          padding: clamp(10px,1.4vw,14px) clamp(20px,2.8vw,32px);
          border-radius: 99px;
          font-weight: 700;
          font-size: clamp(0.8rem, 1.05vw, 0.92rem);
          letter-spacing: 0.03em;
          text-decoration: none;
          white-space: nowrap;
          transition: transform 0.2s ease, box-shadow 0.2s ease;
        }

        .contact-cta:hover {
          box-shadow: 0 6px 22px rgba(34,211,238,0.35);
        }

        /* Full-width button on tiny phones for easy tap */
        @media (max-width: 360px) {
          .contact-cta-row { justify-content: stretch; }
          .contact-cta     { width: 100%; justify-content: center; }
        }

        /* ════════════════════════════════════════════
           FOOTER
           ════════════════════════════════════════════ */
        .contact-footer {
          color: var(--muted);
          font-size: clamp(0.7rem, 0.95vw, 0.8rem);
          margin-top: clamp(2rem, 5vw, 3.5rem);
          text-align: left;
          line-height: 1.6;
          word-break: break-word;
        }

        /* universal safety */
        .contact-section * { box-sizing: border-box; }

      `}</style>

      <section className="contact-section" id="contact">
        <motion.div
          variants={container}
          initial="hidden"
          whileInView="show"
          viewport={{ once: true, margin: "-60px" }}
        >

          {/* ── Header ── */}
          <div className="contact-header">
            <SectionLabel text="Contact" />

            <motion.h2
              className="contact-heading"
              style={{ ...sectionTitle }}
              variants={fadeUp}
            >
              Let's Build Something
            </motion.h2>

            <motion.p className="contact-desc" variants={fadeUp}>
              Available for full-time roles and exciting fintech and enterprise projects.
              Let's connect and build scalable, high-performance systems together.
            </motion.p>
          </div>

          {/* ── Cards ── */}
          <motion.div className="contact-grid" variants={container}>
            {items.map((item, i) => (
              <motion.div
                key={i}
                ref={(el) => (magnetRefs.current[i] = el)}
                className="contact-card"
                variants={fadeUp}
                onMouseMove={(e) => handleMouseMove(e, i)}
                onMouseLeave={() => resetMagnet(i)}
                onClick={() => item.copy && handleCopy(item.value)}
              >
                <span className="contact-icon">{item.icon}</span>
                <span className="contact-lbl">{item.label}</span>

                {item.href ? (
                  <a
                    href={item.href}
                    className={`contact-val${item.copy && copied ? " contact-val--copied" : ""}`}
                    target={item.external ? "_blank" : undefined}
                    rel={item.external ? "noopener noreferrer" : undefined}
                    onClick={(e) => {
                      if (item.copy) { e.preventDefault(); handleCopy(item.value); }
                    }}
                  >
                    {item.copy && copied ? "✓ Copied!" : item.value}
                  </a>
                ) : (
                  <span className="contact-val">{item.value}</span>
                )}
              </motion.div>
            ))}
          </motion.div>

          {/* ── CTA ── */}
          <div className="contact-cta-row">
            <motion.a
              href={`mailto:${contact.email}`}
              className="contact-cta"
              variants={fadeUp}
              whileHover={{ scale: 1.07 }}
              whileTap={{ scale: 0.94 }}
            >
              ✉ Send Email
            </motion.a>
          </div>

          {/* ── Footer ── */}
          <motion.p className="contact-footer" variants={fadeUp}>
            Built with React · Designed to impress · © {new Date().getFullYear()} Akash Chavan
          </motion.p>

        </motion.div>
      </section>
    </>
  );
}
